import time
from ortools.sat.python import cp_model

class JSSP_CP:
    def __init__(self, jobs):
        self.jobs = jobs
        self.num_jobs = len(jobs)
        self.num_machines = max(max(op['machine'] for op in job) for job in self.jobs) + 1
        self.model = cp_model.CpModel()
        self.best_solution = None
        self.best_makespan = float('inf')

    def create_variables(self):
        self.horizon = sum(sum(op['duration'] for op in job) for job in self.jobs)
        self.starts = {}
        self.ends = {}
        self.intervals = {}

        for job_idx, job in enumerate(self.jobs):
            for op_idx, op in enumerate(job):
                machine = op['machine']
                duration = op['duration']
                suffix = f"_j{job_idx}_o{op_idx}"
                start = self.model.NewIntVar(0, self.horizon, f"start{suffix}")
                end = self.model.NewIntVar(0, self.horizon, f"end{suffix}")
                interval = self.model.NewIntervalVar(start, duration, end, f"interval{suffix}")

                self.starts[(job_idx, op_idx)] = start
                self.ends[(job_idx, op_idx)] = end
                self.intervals[(job_idx, op_idx)] = interval

    def add_constraints(self):
        # Machine constraints (no overlap)
        for machine in range(self.num_machines):
            machine_intervals = []
            for job_idx, job in enumerate(self.jobs):
                for op_idx, op in enumerate(job):
                    if op['machine'] == machine:
                        machine_intervals.append(self.intervals[(job_idx, op_idx)])
            self.model.AddNoOverlap(machine_intervals)

        # Precedence constraints (operations in job order)
        for job_idx, job in enumerate(self.jobs):
            for op_idx in range(len(job) - 1):
                self.model.Add(self.ends[(job_idx, op_idx)] <= self.starts[(job_idx, op_idx + 1)])

        # Symmetry breaking: enforce job order on first machine
        first_machine_ops = []
        for job_idx, job in enumerate(self.jobs):
            if job[0]['machine'] == 0:
                first_machine_ops.append((job_idx, 0))
        for i in range(len(first_machine_ops) - 1):
            j1, o1 = first_machine_ops[i]
            j2, o2 = first_machine_ops[i + 1]
            self.model.Add(self.starts[(j1, o1)] <= self.starts[(j2, o2)])

        # Redundant constraints: lower bounds on start times
        for job_idx, job in enumerate(self.jobs):
            cumulative_duration = 0
            for op_idx, op in enumerate(job):
                self.model.Add(self.starts[(job_idx, op_idx)] >= cumulative_duration)
                cumulative_duration += op['duration']

    def add_objective(self):
        makespan = self.model.NewIntVar(0, self.horizon, "makespan")
        max_end = []
        for job_idx, job in enumerate(self.jobs):
            max_end.append(self.ends[(job_idx, len(job) - 1)])
        self.model.AddMaxEquality(makespan, max_end)
        self.model.Minimize(makespan)

    def solve_with_priority_search(self, time_limit=10):
        start_time = time.time()

        solver = cp_model.CpSolver()
        solver.parameters.max_time_in_seconds = time_limit
        solver.parameters.num_search_workers = 4

        status = solver.Solve(self.model)

        if status == cp_model.OPTIMAL or status == cp_model.FEASIBLE:
            makespan = solver.ObjectiveValue()
            if makespan < self.best_makespan:
                self.best_makespan = makespan
                self.best_solution = {}
                for (job_idx, op_idx), var in self.starts.items():
                    self.best_solution[(job_idx, op_idx)] = solver.Value(var)

        return status

    def get_solution(self):
        if self.best_solution is None:
            return None

        scheduled_jobs = []
        for job_idx, job in enumerate(self.jobs):
            scheduled_ops = []
            for op_idx, op in enumerate(job):
                start = self.best_solution.get((job_idx, op_idx), 0)
                scheduled_op = {
                    "machine": op["machine"],
                    "duration": op["duration"],
                    "start": start
                }
                scheduled_ops.append(scheduled_op)
            scheduled_jobs.append(scheduled_ops)

        return scheduled_jobs

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    global _START_TIME, TIMEOUT_SEC

    jssp_solver = JSSP_CP(jobs)
    jssp_solver.create_variables()
    jssp_solver.add_constraints()
    jssp_solver.add_objective()

    time_limit = max(1, TIMEOUT_SEC * 0.8 - (time.time() - _START_TIME))
    status = jssp_solver.solve_with_priority_search(time_limit)

    solution = jssp_solver.get_solution()
    return solution if solution is not None else jobs

