import time
import random
import numpy as np
from ortools.sat.python import cp_model

class JSSP_Hybrid:
    def __init__(self, jobs):
        self.jobs = jobs
        self.num_jobs = len(jobs)
        self.num_machines = max(max(op['machine'] for op in job) for job in self.jobs) + 1
        self.best_solution = None
        self.best_makespan = float('inf')
        self.population_size = 50
        self.mutation_rate = 0.1
        self.elitism_count = 5

    def create_cp_model(self):
        self.model = cp_model.CpModel()
        self.horizon = sum(sum(op['duration'] for op in job) for job in self.jobs)
        self.starts = {}
        self.ends = {}
        self.intervals = {}

        for job_idx, job in enumerate(self.jobs):
            for op_idx, op in enumerate(job):
                machine = op['machine']
                duration = op['duration']
                suffix = f"_j{job_idx}_o{op_idx}"
                start = self.model.NewIntVar(0, self.horizon, f"start{suffix}")
                end = self.model.NewIntVar(0, self.horizon, f"end{suffix}")
                interval = self.model.NewIntervalVar(start, duration, end, f"interval{suffix}")

                self.starts[(job_idx, op_idx)] = start
                self.ends[(job_idx, op_idx)] = end
                self.intervals[(job_idx, op_idx)] = interval

        # Machine constraints
        for machine in range(self.num_machines):
            machine_intervals = []
            for job_idx, job in enumerate(self.jobs):
                for op_idx, op in enumerate(job):
                    if op['machine'] == machine:
                        machine_intervals.append(self.intervals[(job_idx, op_idx)])
            self.model.AddNoOverlap(machine_intervals)

        # Precedence constraints
        for job_idx, job in enumerate(self.jobs):
            for op_idx in range(len(job) - 1):
                self.model.Add(self.ends[(job_idx, op_idx)] <= self.starts[(job_idx, op_idx + 1)])

        # Objective
        makespan = self.model.NewIntVar(0, self.horizon, "makespan")
        max_end = []
        for job_idx, job in enumerate(self.jobs):
            max_end.append(self.ends[(job_idx, len(job) - 1)])
        self.model.AddMaxEquality(makespan, max_end)
        self.model.Minimize(makespan)

    def solve_cp(self, time_limit):
        solver = cp_model.CpSolver()
        solver.parameters.max_time_in_seconds = time_limit
        status = solver.Solve(self.model)

        if status == cp_model.OPTIMAL or status == cp_model.FEASIBLE:
            makespan = solver.ObjectiveValue()
            if makespan < self.best_makespan:
                self.best_makespan = makespan
                self.best_solution = {}
                for (job_idx, op_idx), var in self.starts.items():
                    self.best_solution[(job_idx, op_idx)] = solver.Value(var)

        return status

    def generate_initial_population(self):
        population = []
        for _ in range(self.population_size):
            # Create a random permutation of operations
            operations = []
            for job_idx, job in enumerate(self.jobs):
                for op_idx, op in enumerate(job):
                    operations.append((job_idx, op_idx))
            random.shuffle(operations)
            population.append(operations)
        return population

    def evaluate_fitness(self, individual):
        # Create a temporary CP model with fixed operation order
        temp_model = cp_model.CpModel()
        temp_starts = {}
        temp_ends = {}

        # Create variables
        for job_idx, job in enumerate(self.jobs):
            for op_idx, op in enumerate(job):
                duration = op['duration']
                start = temp_model.NewIntVar(0, self.horizon, f"start_j{job_idx}_o{op_idx}")
                end = temp_model.NewIntVar(0, self.horizon, f"end_j{job_idx}_o{op_idx}")
                temp_starts[(job_idx, op_idx)] = start
                temp_ends[(job_idx, op_idx)] = end
                temp_model.Add(end == start + duration)

        # Add precedence constraints based on individual's order
        for i in range(len(individual) - 1):
            job1, op1 = individual[i]
            job2, op2 = individual[i + 1]
            if job1 == job2:  # Same job, must maintain order
                if op1 > op2:
                    return float('inf')  # Invalid individual
            else:  # Different jobs, can be in any order
                pass

        # Add machine constraints
        for machine in range(self.num_machines):
            machine_ops = []
            for job_idx, job in enumerate(self.jobs):
                for op_idx, op in enumerate(job):
                    if op['machine'] == machine:
                        machine_ops.append((job_idx, op_idx))

            # Sort operations on this machine according to individual's order
            machine_ops_sorted = sorted(machine_ops, key=lambda x: individual.index(x))

            for i in range(len(machine_ops_sorted) - 1):
                job1, op1 = machine_ops_sorted[i]
                job2, op2 = machine_ops_sorted[i + 1]
                temp_model.Add(temp_ends[(job1, op1)] <= temp_starts[(job2, op2)])

        # Add job precedence constraints
        for job_idx, job in enumerate(self.jobs):
            for op_idx in range(len(job) - 1):
                temp_model.Add(temp_ends[(job_idx, op_idx)] <= temp_starts[(job_idx, op_idx + 1)])

        # Solve to get makespan
        solver = cp_model.CpSolver()
        solver.parameters.max_time_in_seconds = 1  # Quick evaluation
        status = solver.Solve(temp_model)

        if status == cp_model.OPTIMAL or status == cp_model.FEASIBLE:
            makespan = max(solver.Value(temp_ends[(job_idx, len(job)-1)]) for job_idx, job in enumerate(self.jobs))
            return makespan
        return float('inf')

    def crossover(self, parent1, parent2):
        # Ordered crossover (OX)
        size = len(parent1)
        a, b = sorted(random.sample(range(size), 2))

        child = [None] * size
        child[a:b] = parent1[a:b]

        ptr = b
        for gene in parent2[b:] + parent2[:b]:
            if gene not in child[a:b]:
                child[ptr % size] = gene
                ptr += 1

        return child

    def mutate(self, individual):
        # Swap mutation
        if random.random() < self.mutation_rate:
            a, b = random.sample(range(len(individual)), 2)
            individual[a], individual[b] = individual[b], individual[a]
        return individual

    def genetic_algorithm(self, time_limit):
        start_time = time.time()
        population = self.generate_initial_population()

        while time.time() - start_time < time_limit:
            # Evaluate fitness
            fitness = [self.evaluate_fitness(ind) for ind in population]

            # Check for new best solution
            current_best = min(fitness)
            if current_best < self.best_makespan:
                best_idx = fitness.index(current_best)
                # Convert GA solution to CP solution format
                temp_solution = {}
                current_time = [0] * self.num_jobs

                for job_idx, op_idx in population[best_idx]:
                    machine = self.jobs[job_idx][op_idx]['machine']
                    duration = self.jobs[job_idx][op_idx]['duration']

                    # Find earliest start time considering job precedence and machine availability
                    job_start = current_time[job_idx]
                    machine_start = 0

                    # Check machine availability (simplified)
                    for other_job_idx in range(self.num_jobs):
                        if other_job_idx != job_idx:
                            # This is a simplified check - in reality would need to track all operations
                            pass

                    start = max(job_start, machine_start)
                    temp_solution[(job_idx, op_idx)] = start
                    current_time[job_idx] = start + duration

                self.best_solution = temp_solution
                self.best_makespan = current_best

            # Selection (tournament selection)
            new_population = []
            for _ in range(self.population_size - self.elitism_count):
                # Tournament selection
                tournament = random.sample(list(zip(population, fitness)), 3)
                winner = min(tournament, key=lambda x: x[1])[0]
                new_population.append(winner)

            # Elitism - keep best individuals
            elite_indices = sorted(range(len(fitness)), key=lambda i: fitness[i])[:self.elitism_count]
            for idx in elite_indices:
                new_population.append(population[idx])

            # Crossover and mutation
            next_generation = []
            for i in range(0, len(new_population), 2):
                if i + 1 < len(new_population):
                    child1 = self.crossover(new_population[i], new_population[i+1])
                    child2 = self.crossover(new_population[i+1], new_population[i])
                    next_generation.extend([self.mutate(child1), self.mutate(child2)])
                else:
                    next_generation.append(self.mutate(new_population[i]))

            population = next_generation

        return min(fitness) if fitness else float('inf')

    def get_solution(self):
        if self.best_solution is None:
            return None

        scheduled_jobs = []
        for job_idx, job in enumerate(self.jobs):
            scheduled_ops = []
            for op_idx, op in enumerate(job):
                start = self.best_solution.get((job_idx, op_idx), 0)
                scheduled_op = {
                    "machine": op["machine"],
                    "duration": op["duration"],
                    "start": start
                }
                scheduled_ops.append(scheduled_op)
            scheduled_jobs.append(scheduled_ops)

        return scheduled_jobs

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    global _START_TIME, TIMEOUT_SEC

    jssp_solver = JSSP_Hybrid(jobs)
    jssp_solver.create_cp_model()

    # Allocate time for both approaches
    total_time = TIMEOUT_SEC * 0.8
    cp_time = total_time * 0.6
    ga_time = total_time * 0.4

    # First run CP solver
    remaining_time = max(0, cp_time - (time.time() - _START_TIME))
    if remaining_time > 0:
        jssp_solver.solve_cp(remaining_time)

    # Then run GA to potentially improve
    remaining_time = max(0, ga_time - (time.time() - _START_TIME))
    if remaining_time > 0:
        jssp_solver.genetic_algorithm(remaining_time)

    solution = jssp_solver.get_solution()
    return solution if solution is not None else jobs
